 1	import * as React from "react";
 2	
 3	import { Action } from "@openshift-console/dynamic-plugin-sdk";
 4	// import { LazyActionMenu } from '@openshift-console/dynamic-plugin-sdk-internal';
 5	import {
 6	  Dropdown,
 7	  DropdownItem,
 8	  DropdownList,
 9	  MenuToggle,
10	  MenuToggleElement,
11	} from "@patternfly/react-core";
12	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
13	import { EllipsisVIcon } from "@patternfly/react-icons";
14	
15	export type ActionsMenuProps = {
16	  actions: Action[];
17	  isKababToggle: boolean;
18	};
19	
20	const ActionsMenu: React.FC<ActionsMenuProps> = ({
21	  actions,
22	  isKababToggle,
23	}) => {
24	  const { t } = useNodeHealthCheckTranslation();
25	  const [isOpen, setIsOpen] = React.useState(false);
26	
27	  const handleClick = (action: Action) => {
28	    if (typeof action?.cta === "function") {
29	      action?.cta();
30	      setIsOpen(false);
31	    }
32	  };
33	
34	  const onToggleClick = () => setIsOpen(!isOpen);
35	
36	  return (
37	    <Dropdown
38	      data-test-id="actions"
39	      isOpen={isOpen}
40	      onOpenChange={setIsOpen}
41	      popperProps={{
42	        position: "right",
43	      }}
44	      toggle={(toggleRef: React.Ref<MenuToggleElement>) =>
45	        isKababToggle ? (
46	          <MenuToggle
47	            ref={toggleRef}
48	            aria-label="kebab dropdown toggle"
49	            variant="plain"
50	            onClick={onToggleClick}
51	            isExpanded={isOpen}
52	          >
53	            <EllipsisVIcon />
54	          </MenuToggle>
55	        ) : (
56	          <MenuToggle
57	            ref={toggleRef}
58	            onClick={onToggleClick}
59	            isExpanded={isOpen}
60	          >
61	            {t("Actions")}
62	          </MenuToggle>
63	        )
64	      }
65	    >
66	      <DropdownList>
67	        {actions?.map((action) => (
68	          <DropdownItem
69	            data-test-id={`${action.id}`}
70	            key={action?.id}
71	            onClick={() => handleClick(action)}
72	            isDisabled={action?.disabled}
73	            description={action?.description}
74	            component="button"
75	          >
76	            {action?.label}
77	          </DropdownItem>
78	        ))}
79	      </DropdownList>
80	    </Dropdown>
81	  );
82	};
83	
84	export default ActionsMenu;

